def cache(seconds):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = func.__name__ + str(args) + str(kwargs)
            value = redis.get(key)
            if value is None:
                value = func(*args, **kwargs)
                redis.set(key, value, seconds)
            return value
        return wrapper
    return decorator

